// ── INITIALISE RUN CONTEXT ─────────────────────────────────────
// Creates a run_id, timestamps, and config for this pipeline execution.

const now       = new Date();
const run_id    = `RUN_${now.toISOString().replace(/[:\-.TZ]/g, '').slice(0,15)}`;
const weekStart = new Date(now); weekStart.setDate(now.getDate() - 7);

return [{
  json: {
    run_id,
    pipeline_name:  'enterprise-data-pipeline',
    triggered_at:   now.toISOString(),
    week_start:     weekStart.toISOString().slice(0,10),
    week_end:       now.toISOString().slice(0,10),
    env:            'production',
    version:        '2.0.0',
    config: {
      api_url:        'https://jsonplaceholder.typicode.com/posts',
      max_records:    100,
      min_records:    5,
      retry_attempts: 3,
      timeout_ms:     15000
    }
  }
}];

// ── SCHEMA VALIDATION ──────────────────────────────────────────
// Validate that the API returned usable data before processing.

const ctx    = $('🔧 Initialise Run Context').first().json;
const raw    = $input.all();

const errors  = [];
const valid   = [];

for (const item of raw) {
  const rec = item.json;
  const recErrors = [];

  // Required field checks
  if (!rec.id)                      recErrors.push('missing id');
  if (!rec.title || rec.title.trim() === '') recErrors.push('empty title');
  if (!rec.body  || rec.body.trim()  === '') recErrors.push('empty body');
  if (rec.userId === undefined)     recErrors.push('missing userId');

  // Type checks
  if (rec.id && typeof rec.id !== 'number') recErrors.push('id must be number');

  if (recErrors.length > 0) {
    errors.push({ id: rec.id, errors: recErrors });
  } else {
    valid.push(rec);
  }
}

if (valid.length < ctx.config.min_records) {
  throw new Error(`Validation failed: only ${valid.length} valid records (minimum ${ctx.config.min_records})`);
}

return [{
  json: {
    run_id:           ctx.run_id,
    triggered_at:     ctx.triggered_at,
    config:           ctx.config,
    validation: {
      total_raw:      raw.length,
      valid_records:  valid.length,
      invalid_records:errors.length,
      invalid_details:errors.slice(0, 10),
      pass_rate:      ((valid.length / raw.length) * 100).toFixed(1) + '%'
    },
    rawData: valid
  }
}];

// ── PROFESSIONAL DATA CLEANING ─────────────────────────────────
const input   = $input.first().json;
const records = input.rawData;

const cleaned = records.map(rec => {
  const title = rec.title.trim().replace(/\s+/g, ' ');
  const body  = rec.body.trim().replace(/\s+/g, ' ');

  // Compute features
  const wordCount   = body.split(/\s+/).filter(Boolean).length;
  const titleLen    = title.length;
  const sentiment   = wordCount > 30 ? 'long' : wordCount > 15 ? 'medium' : 'short';
  const userId      = Number(rec.userId);

  return {
    id:             rec.id,
    title:          title,
    title_length:   titleLen,
    body_preview:   body.substring(0, 120) + (body.length > 120 ? '...' : ''),
    word_count:     wordCount,
    content_length: sentiment,
    user_id:        userId,
    user_tier:      userId <= 3 ? 'premium' : userId <= 7 ? 'standard' : 'basic',
    processed_at:   new Date().toISOString()
  };
});

// Aggregate stats
const totalWords   = cleaned.reduce((s, r) => s + r.word_count, 0);
const avgWords     = Math.round(totalWords / cleaned.length);
const byTier       = cleaned.reduce((acc, r) => { acc[r.user_tier] = (acc[r.user_tier] || 0) + 1; return acc; }, {});
const byContent    = cleaned.reduce((acc, r) => { acc[r.content_length] = (acc[r.content_length] || 0) + 1; return acc; }, {});
const uniqueUsers  = [...new Set(cleaned.map(r => r.user_id))].length;

return [{
  json: {
    run_id:       input.run_id,
    triggered_at: input.triggered_at,
    validation:   input.validation,
    cleaned_data: cleaned,
    kpis: {
      total_records:   cleaned.length,
      unique_users:    uniqueUsers,
      avg_word_count:  avgWords,
      by_user_tier:    byTier,
      by_content_len:  byContent,
      processing_time: new Date().toISOString()
    }
  }
}];

const input = $input.first().json;
const msg = `[${input.run_id}] QUALITY GATE FAILED: only ${input.validation.valid_records}/${input.validation.total_raw} records passed validation (required: 80%). Pipeline halted.`;
console.error(msg);
return [{ json: { run_id: input.run_id, status: 'failed', reason: 'quality_gate', message: msg, details: input.validation, timestamp: new Date().toISOString() } }];

// ── FINAL AGGREGATION ──────────────────────────────────────────
const allItems  = $input.all();
const allData   = allItems.flatMap(item => Array.isArray(item.json) ? item.json : [item.json]);

// Pass through cleanly merged data
const merged    = allData.filter(d => d.id !== undefined);
const ctx       = $('🧹 Clean & Transform Data').first().json;

return [{
  json: {
    run_id:       ctx.run_id,
    triggered_at: ctx.triggered_at,
    kpis:         ctx.kpis,
    validation:   ctx.validation,
    final_records:merged.length,
    cleaned_data: merged.slice(0, 50),  // top 50 for report
    report_ready: true
  }
}];

// ── CENTRALISED ERROR HANDLER ──────────────────────────────────
const err = $input.first().json;
const ctx = {};

const errorPayload = {
  run_id:     err.run_id || 'UNKNOWN',
  status:     'failed',
  error_type: err.reason || 'pipeline_error',
  message:    err.message || JSON.stringify(err),
  timestamp:  new Date().toISOString(),
  alert_sent: true
};

console.error('[PIPELINE ERROR]', JSON.stringify(errorPayload, null, 2));
return [{ json: errorPayload }];
